/// Streaming handle for `DefaultClient::chat_stream` — owns a Tokio runtime
/// plus the live `BoxStream`. Each call to `defaultclient_chat_stream_next` blocks the dirty-CPU
/// scheduler thread on a single `stream.next()` poll.
pub struct DefaultClientChatStreamHandle {
    runtime: std::sync::Arc<tokio::runtime::Runtime>,
    stream: std::sync::Mutex<
        Option<
            futures_util::stream::BoxStream<
                'static,
                std::result::Result<liter_llm::ChatCompletionChunk, liter_llm::LiterLlmError>,
            >,
        >,
    >,
}

#[rustler::resource_impl()]
impl rustler::Resource for DefaultClientChatStreamHandle {}

/// Open a streaming `chat_stream` request. Returns an opaque iterator
/// resource which the Elixir wrapper drives via `Stream.unfold/2`.
#[rustler::nif(schedule = "DirtyCpu")]
pub fn defaultclient_chat_stream_start(
    resource: rustler::ResourceArc<DefaultClient>,
    req: Option<String>,
) -> std::result::Result<rustler::ResourceArc<DefaultClientChatStreamHandle>, String> {
    let core_req: liter_llm::ChatCompletionRequest = req
        .map(|s| serde_json::from_str::<liter_llm::ChatCompletionRequest>(&s))
        .transpose()
        .map_err(|e| e.to_string())?
        .unwrap_or_default();
    let runtime = std::sync::Arc::new(
        tokio::runtime::Builder::new_multi_thread()
            .enable_all()
            .build()
            .map_err(|e| e.to_string())?,
    );
    let inner = resource.inner.clone();
    let stream = runtime
        .block_on(async move { inner.chat_stream(core_req).await })
        .map_err(|e| e.to_string())?;
    let handle = DefaultClientChatStreamHandle {
        runtime,
        stream: std::sync::Mutex::new(Some(stream)),
    };
    Ok(rustler::ResourceArc::new(handle))
}

/// Pull the next chunk from a streaming handle. Returns the chunk JSON
/// (decoded by the Elixir wrapper via `Jason.decode!/1`) or `nil` to
/// signal end-of-stream. After end-of-stream the inner stream is dropped.
#[rustler::nif(schedule = "DirtyCpu")]
pub fn defaultclient_chat_stream_next(
    handle: rustler::ResourceArc<DefaultClientChatStreamHandle>,
) -> std::result::Result<Option<String>, String> {
    use futures_util::StreamExt;
    let runtime = handle.runtime.clone();
    let mut guard = handle.stream.lock().map_err(|e| e.to_string())?;
    let stream_ref = match guard.as_mut() {
        Some(s) => s,
        None => return Ok(None),
    };
    match runtime.block_on(stream_ref.next()) {
        Some(Ok(chunk)) => {
            let json = serde_json::to_string(&chunk).map_err(|e| e.to_string())?;
            Ok(Some(json))
        }
        Some(Err(e)) => {
            *guard = None;
            Err(e.to_string())
        }
        None => {
            *guard = None;
            Ok(None)
        }
    }
}

/// Create a new LLM client with simple scalar configuration.
///
/// This is the primary binding entry-point. All parameters except `api_key`
/// are optional — omitting them uses the same defaults as
/// [`ClientConfigBuilder`].
///
/// # Errors
///
/// Returns [`LiterLlmError`] if the underlying HTTP client cannot be
/// constructed, or if the resolved provider configuration is invalid.
#[rustler::nif]
pub fn create_client(
    api_key: String,
    base_url: Option<String>,
    timeout_secs: Option<u64>,
    max_retries: Option<u32>,
    model_hint: Option<String>,
) -> Result<ResourceArc<DefaultClient>, String> {
    let result = liter_llm::create_client(api_key, base_url, timeout_secs, max_retries, model_hint)
        .map_err(|e| e.to_string())?;
    Ok(ResourceArc::new(DefaultClient {
        inner: Arc::new(result),
    }))
}

/// Create a new LLM client from a JSON string.
///
/// The JSON object accepts the same fields as `liter-llm.toml` (snake_case).
///
/// # Errors
///
/// Returns [`LiterLlmError::BadRequest`] if `json` is not valid JSON or
/// contains unknown fields.
#[rustler::nif]
pub fn create_client_from_json(json: String) -> Result<ResourceArc<DefaultClient>, String> {
    let result = liter_llm::create_client_from_json(&json).map_err(|e| e.to_string())?;
    Ok(ResourceArc::new(DefaultClient {
        inner: Arc::new(result),
    }))
}

/// Register a custom provider in the global runtime registry.
///
/// The provider will be checked **before** all built-in providers during model
/// detection. If a provider with the same `name` already exists it is replaced.
///
/// # Errors
///
/// Returns an error if the config is invalid (empty name, empty base_url, or
/// no model prefixes).
#[rustler::nif]
pub fn register_custom_provider(config: CustomProviderConfig) -> Result<(), String> {
    let result = liter_llm::provider::custom::register_custom_provider(config.into()).map_err(|e| e.to_string())?;
    Ok(result)
}

/// Remove a previously registered custom provider by name.
///
/// Returns `true` if a provider with the given name was found and removed,
/// `false` if no such provider existed.
///
/// # Errors
///
/// Returns an error only if the internal lock is poisoned.
#[rustler::nif]
pub fn unregister_custom_provider(name: String) -> Result<bool, String> {
    let result = liter_llm::provider::custom::unregister_custom_provider(&name).map_err(|e| e.to_string())?;
    Ok(result)
}

/// Return all provider configs from the registry.
///
/// Useful for tooling, documentation generation, or runtime enumeration.
#[rustler::nif]
pub fn all_providers() -> Result<Vec<ProviderConfig>, String> {
    let result = liter_llm::provider::all_providers().map_err(|e| e.to_string())?;
    Ok(result.iter().cloned().map(Into::into).collect())
}

/// Return the set of complex provider names.
///
/// Complex providers require custom auth/routing logic beyond simple bearer
